```class Solution {
public:
    vector<int> maxScoreIndices(vector<int>& nums) {
        int n = nums.size();
        vector<int> left(n + 1, 0), right(n + 1, 0);
        for (int i = 0; i < n; i++) {
            left[i + 1] = left[i] + (1 - nums[i]);
            right[n - i - 1] = right[n - i] + nums[n - i - 1];
        }
        int maxScore = 0;
        vector<int> res;
        for (int i = 0; i <= n; i++) {
            int score = left[i] + right[i];
            if (score > maxScore) {
                maxScore = score;
                res.clear();
                res.push_back(i);
            } else if (score == maxScore) {
                res.push_back(i);
            }
        }
        return res;
    }
};
